    var roleResponse = openidm.query(
        "managed/alpha_role",
        {
            "_queryFilter": 'businessRoleId eq "' + sourceRoleId + '"'
        },
        ["_id"]
    );
    if (!roleResponse.result || roleResponse.result.length === 0) {
        throw "role not found";
    }
    var roleIdRef = roleResponse.result[0]._id;
    var appResponse = openidm.query(
        "managed/alpha_kyid_businessapplication",
        {
            "_queryFilter": 'name eq "' + sourceKogParentName + '"'
        },
        ["_id"]
    );
    if (appResponse.result && appResponse.result.length == 1) {
		var appId = appResponse.result[0]._id;
		var appRef = { "_ref": "managed/alpha_kyid_businessapplication/" + appId };
    } else {
		logger.error("Exception occurred during role to business link for : "+sourceKogParentName  );
    }
} catch (e) {
    logger.error("Exception occurred: " + e);  
